module adder_pipe_64bit(
    input clk,
    input rst_n,
    input i_en,
    input [63:0] adda,
    input [63:0] addb,
    output reg [64:0] result,
    output o_en
);
    //adda and addb
    reg [63:0] adda_reg, addb_reg;
    reg [63:0] adda_reg_1, addb_reg_1;
    reg [63:0] adda_reg_2, addb_reg_2;
    reg [63:0] adda_reg_3, addb_reg_3;
    always @(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            adda_reg <= 0;
            addb_reg <= 0;
        end
        else begin
            if(i_en) begin
                adda_reg <= adda;
                addb_reg <= addb;
            end
        end
    end
    always @(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            adda_reg_1 <= 0;
            addb_reg_1 <= 0;
        end
        else begin
            adda_reg_1 <= adda_reg;
            addb_reg_1 <= addb_reg;
        end
    end
    always @(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            adda_reg_2 <= 0;
            addb_reg_2 <= 0;
        end
        else begin
            adda_reg_2 <= adda_reg_1;
            addb_reg_2 <= addb_reg_1;
        end
    end
    always @(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            adda_reg_3 <= 0;
            addb_reg_3 <= 0;
        end
        else begin
            adda_reg_3 <= adda_reg_2;
            addb_reg_3 <= addb_reg_2;
        end
    end
    //c_reg
    reg [64:0] c_reg, c_reg_1, c_reg_2, c_reg_3;
    wire [64:0] sum_reg_temp;
    wire [64:0] carry_out_temp;
    assign sum_reg_temp = {1'b0,adda_reg_3} + {1'b0,addb_reg_3} + c_reg[64];
    assign carry_out_temp = {1'b0,adda_reg_3} + {1'b0,addb_reg_3};
    always @(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            c_reg <= 0;
        end
        else begin
            c_reg <= carry_out_temp;
        end
    end
    always @(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            c_reg_1 <= 0;
        end
        else begin
            c_reg_1 <= c_reg;
        end
    end
    always @(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            c_reg_2 <= 0;
        end
        else begin
            c_reg_2 <= c_reg_1;
        end
    end
    always @(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            c_reg_3 <= 0;
        end
        else begin
            c_reg_3 <= c_reg_2;
        end
    end
    //sum_reg
    reg [64:0] sum_reg;
    always @(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            sum_reg <= 0;
        end
        else begin
            sum_reg <= sum_reg_temp;
        end
    end
    //i_en_reg
    reg i_en_reg;
    reg i_en_reg_1;
    reg i_en_reg_2;
    reg i_en_reg_3;
    always @(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            i_en_reg <= 0;
        end
        else begin
            if(i_en) i_en_reg <= i_en;
        end
    end
    always @(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            i_en_reg_1 <= 0;
        end
        else begin
            i_en_reg_1 <= i_en_reg;
        end
    end
    always @(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            i_en_reg_2 <= 0;
        end
        else begin
            i_en_reg_2 <= i_en_reg_1;
        end
    end
    always @(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            i_en_reg_3 <= 0;
        end
        else begin
            i_en_reg_3 <= i_en_reg_2;
        end
    end
    //o_en_reg
    reg o_en_reg, o_en_reg_1, o_en_reg_2, o_en_reg_3;
    always @(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            o_en_reg <= 0;
        end
        else begin
            if(i_en) o_en_reg <= 0;
        end
    end
    always @(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            o_en_reg_1 <= 0;
        end
        else begin
            o_en_reg_1 <= o_en_reg;
        end
    end
    always @(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            o_en_reg_2 <= 0;
        end
        else begin
            o_en_reg_2 <= o_en_reg_1;
        end
    end
    always @(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            o_en_reg_3 <= 0;
        end
        else begin
            o_en_reg_3 <= o_en_reg_2;
        end
    end
    always @(*) begin
        if(i_en_reg_3) o_en = 1;
        else o_en = 0;
    end
    always @(*) begin
        if(o_en_reg_3) begin
            result = sum_reg;
        end
        else result = 0;
    end
endmodule
